(function($){function closeAll(){$('.spid-idp-button').removeClass('spid-open')}$(document).on('click','[spid-idp-button]',function(e){e.preventDefault();var t=$(this).attr('spid-idp-button'),$m=$(t);if(!$m.length)return;var open=$m.hasClass('spid-open');closeAll();if(!open){$m.addClass('spid-open')}});$(document).on('click',function(e){if(!$(e.target).closest('[spid-idp-button],.spid-idp-button').length){closeAll()}})})(jQuery);
